class Solution {
    public long minimumSteps(String s) {
        int n = s.length();
        int countBlack = 0;
        int countWhite = n - countBlack;

        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '0') {
                countBlack++;
            } else {
                countWhite--;
            }
        }

        long steps = countWhite * (countWhite - 1) / 2 + countBlack;

        return steps;
    }
}
```

